import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type RegexpProps = IconProps;

const RegexpLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect
      x="2.5"
      y="2.5"
      width="11"
      height="11"
      rx="1.5"
      fill="#EBECF0"
      stroke="#6C707E"
    />
    <path
      d="M4 10.5a.5.5 0 0 1 .5-.5h1a.5.5 0 0 1 .5.5v1a.5.5 0 0 1-.5.5h-1a.5.5 0 0 1-.5-.5z"
      fill="#6C707E"
    />
    <path
      d="M9.5 4.5V7m0 0 1.47 2.023M9.5 7 8.03 9.023M9.5 7l-2.378-.773M9.5 7l2.377-.773"
      stroke="#6C707E"
      strokeLinecap="round"
    />
  </svg>
);

const RegexpDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect
      x="2.5"
      y="2.5"
      width="11"
      height="11"
      rx="1.5"
      fill="#43454A"
      stroke="#CED0D6"
    />
    <path d="M5.5 10.5v1h-1v-1z" fill="#CED0D6" stroke="#CED0D6" />
    <path
      d="M9.5 4.5V7m0 0 1.47 2.023M9.5 7 8.03 9.023M9.5 7l-2.378-.773M9.5 7l2.377-.773"
      stroke="#CED0D6"
      strokeLinecap="round"
    />
  </svg>
);

export const Regexp: FC<RegexpProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? RegexpLight : RegexpDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
